Fix the bug in this `groupBy` implementation. The function should partition an array into groups keyed by the result of `keyFn`, returning a `Record<string, T[]>` where each value is the subset of items that produced that key. Every item must appear in exactly one group.

```ts
export function groupBy<T>(arr: T[], keyFn: (x: T) => string): Record<string, T[]> {
  const result: Record<string, T[]> = {};
  const defaultArr: T[] = [];
  for (const item of arr) {
    const k = keyFn(item);
    result[k] = result[k] || defaultArr;
    result[k].push(item);
  }
  return result;
}
```
